import java.util.concurrent.*;
public class SemaphoreDemo {
    static Semaphore sem = new Semaphore(2);
    static java.util.concurrent.atomic.AtomicInteger active = 
        new java.util.concurrent.atomic.AtomicInteger(0);
    public static void main(String[] args) throws Exception {
        Runnable task = () -> {
            try {
                sem.acquire();
                active.incrementAndGet();
                Thread.sleep(50);
                active.decrementAndGet();
                sem.release();
            } catch (InterruptedException e) {}
        };
        Thread[] ts = {new Thread(task), new Thread(task), new Thread(task)};
        for (Thread t : ts) t.start();
        Thread.sleep(10);
        System.out.println(active.get() <= 2);
        for (Thread t : ts) t.join();
        System.out.println(active.get());
    }
}
